30	    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
31	    pub file: std::path::PathBuf,
32	
33	    /// Target: Firemark (heat view) or Coronet (pace view). If omitted, uses first racing heat.
34	    pub target: Option<String>,
