45	/// Run the show command - display comprehensive Heat status
46	pub fn jjrpd_run_parade(args: jjrpd_ParadeArgs, gazette: &mut jjrz_Gazette) -> (i32, String) {
47	    let cn = JJRPD_CMD_NAME_SHOW;
48	    let mut output = vvco_Output::buffer();
49	
50	    // Disk space guard — report survey or block if critical
51	    match crate::jjrdk_diskcheck::jjrdk_check_disk_space() {
52	        Ok(survey) => vvco_out!(output, "{}", survey),
53	        Err(msg) => {
54	            vvco_err!(output, "{}", msg);
55	            return (1, output.vvco_finish());
56	        }
57	    }
58	
59	    let gallops = match Gallops::jjrg_load(&args.file) {
60	        Ok(g) => g,
