62	            vvco_err!(output, "{}: error: {}", cn, e);
63	            return (1, output.vvco_finish());
64	        }
65	    };
66	
67	    // Resolve target: use provided value or auto-select first racing heat
68	    let target = match args.target {
69	        Some(t) => t,
