102	                return (1, output.vvco_finish());
103	            }
104	        };
105	
106	        // Find pace
107	        let coronet_key = coronet.jjrf_display();
108	        let pace = match heat.paces.get(&coronet_key) {
109	            Some(p) => p,
110	            None => {
111	                vvco_err!(output, "{}: error: Pace '{}' not found in Heat '{}'", cn, coronet_key, heat_key);
112	                return (1, output.vvco_finish());
113	            }
114	        };
115	
116	        // Display pace view
