210	            vvco_out!(output, "");
211	            gazette_paddock = Some(paddock_content);
212	            vvco_out!(output, "");
213	            vvco_out!(output, "## Paces");
214	            vvco_out!(output, "");
215	
216	            for coronet_key in &heat.order {
217	                if let Some(pace) = heat.paces.get(coronet_key) {
218	                    if let Some(tack) = pace.tacks.first() {
219	                        // Skip complete/abandoned if --remaining
220	                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
221	                            continue;
222	                        }
223	                        let state_str = zjjrpd_pace_state_str(&tack.state);
224	                        vvco_out!(output, "### {} ({}) [{}]", tack.silks, coronet_key, state_str);
225	                        vvco_out!(output, "");
226	                        vvco_out!(output, "{}", tack.text);
227	                        if let Some(ref direction) = tack.direction {
228	                            vvco_out!(output, "");
229	                            vvco_out!(output, "**Warrant:** {}", direction);
230	                        }
231	                        vvco_out!(output, "");
232	                    }
233	                }
234	            }
235	        } else {
236	            // List view: numbered paces
237	            // If --remaining, output markdown format
238	            if args.remaining {
239	                let mut complete_count = 0;
240	                let mut abandoned_count = 0;
241	                let mut rough_count = 0;
242	                let mut bridled_count = 0;
243	                let mut remaining_paces: Vec<(&String, &crate::jjrg_gallops::jjrg_Pace)> = Vec::new();
244	                let mut first_remaining_pace: Option<(&String, &crate::jjrg_gallops::jjrg_Pace)> = None;
245	
246	                for coronet_key in &heat.order {
247	                    if let Some(pace) = heat.paces.get(coronet_key) {
248	                        if let Some(tack) = pace.tacks.first() {
249	                            match tack.state {
250	                                PaceState::Complete => complete_count += 1,
251	                                PaceState::Abandoned => abandoned_count += 1,
252	                                PaceState::Rough => {
253	                                    rough_count += 1;
254	                                    remaining_paces.push((coronet_key, pace));
255	                                    if first_remaining_pace.is_none() {
256	                                        first_remaining_pace = Some((coronet_key, pace));
257	                                    }
258	                                }
259	                                PaceState::Bridled => {
260	                                    bridled_count += 1;
261	                                    remaining_paces.push((coronet_key, pace));
262	                                    if first_remaining_pace.is_none() {
263	                                        first_remaining_pace = Some((coronet_key, pace));
264	                                    }
265	                                }
266	                            }
267	                        }
268	                    }
269	                }
270	
271	                let status_str = match heat.status {
272	                    HeatStatus::Racing => "racing",
273	                    HeatStatus::Stabled => "stabled",
274	                    HeatStatus::Retired => "retired",
275	                };
276	
277	                let remaining_count = rough_count + bridled_count;
278	
279	                // Header line with heat info
280	                vvco_out!(output, "Heat: {} ({}) [{}]", heat.silks, heat_key, status_str);
281	                vvco_out!(output, "Progress: {} complete | {} abandoned | {} remaining ({} rough, {} bridled)",
282	                    complete_count, abandoned_count, remaining_count, rough_count, bridled_count);
283	                vvco_out!(output, "");
284	
285	                // Table with remaining paces
286	                if !remaining_paces.is_empty() {
287	                    // Set up table with column definitions
288	                    let mut table = jjrp_Table::jjrp_new(vec![
289	                        jjrp_Column::new("No", jjrp_Align::Right),
290	                        jjrp_Column::new("State", jjrp_Align::Left),
291	                        jjrp_Column::new("Pace", jjrp_Align::Left),
292	                        jjrp_Column::new("₢Coronet", jjrp_Align::Left),
293	                    ]);
294	
295	                    // Measure all rows to compute column widths
296	                    for (idx, (coronet_key, pace)) in remaining_paces.iter().enumerate() {
297	                        if let Some(tack) = pace.tacks.first() {
298	                            let state_str = zjjrpd_pace_state_str(&tack.state);
299	                            table.jjrp_measure(&[
300	                                &(idx + 1).to_string(),
301	                                state_str,
302	                                &tack.silks,
303	                                coronet_key,
304	                            ]);
305	                        }
306	                    }
307	
308	                    // Write header and separator
309	                    table.jjrp_write_header(&mut output);
310	                    table.jjrp_write_separator(&mut output);
311	
312	                    // Write data rows
313	                    for (idx, (coronet_key, pace)) in remaining_paces.iter().enumerate() {
314	                        if let Some(tack) = pace.tacks.first() {
315	                            let state_str = zjjrpd_pace_state_str(&tack.state);
316	                            table.jjrp_write_row(&mut output, &[
317	                                &(idx + 1).to_string(),
318	                                state_str,
319	                                &tack.silks,
320	                                coronet_key,
321	                            ]);
322	                        }
323	                    }
324	                    vvco_out!(output, "");
325	                }
326	
327	                // Next up callout
328	                if let Some((coronet_key, pace)) = first_remaining_pace {
329	                    if let Some(tack) = pace.tacks.first() {
330	                        let state_str = zjjrpd_pace_state_str(&tack.state);
331	                        vvco_out!(output, "Next: {} ({}) [{}]", tack.silks, coronet_key, state_str);
332	                        vvco_out!(output, "");
333	                        vvco_out!(output, "Recommended: mount {}", heat_key);
334	                    }
335	                }
336	            } else {
337	                // Column-justified list view (all paces)
338	                // Set up table with column definitions
339	                let mut table = jjrp_Table::jjrp_new(vec![
340	                    jjrp_Column::new("No", jjrp_Align::Right),
341	                    jjrp_Column::new("State", jjrp_Align::Left),
342	                    jjrp_Column::new("Pace", jjrp_Align::Left),
343	                    jjrp_Column::new("₢Coronet", jjrp_Align::Left),
344	                ]);
345	
346	                // Measure all rows to compute column widths
347	                let mut num = 0;
348	                for coronet_key in &heat.order {
349	                    if let Some(pace) = heat.paces.get(coronet_key) {
350	                        if let Some(tack) = pace.tacks.first() {
351	                            num += 1;
352	                            let state_str = zjjrpd_pace_state_str(&tack.state);
353	                            table.jjrp_measure(&[
354	                                &num.to_string(),
355	                                state_str,
356	                                &tack.silks,
357	                                coronet_key,
358	                            ]);
359	                        }
360	                    }
361	                }
362	
363	                // Write header and separator
364	                table.jjrp_write_header(&mut output);
365	                table.jjrp_write_separator(&mut output);
366	
367	                // Write data rows
368	                let mut num = 0;
369	                for coronet_key in &heat.order {
370	                    if let Some(pace) = heat.paces.get(coronet_key) {
371	                        if let Some(tack) = pace.tacks.first() {
372	                            num += 1;
373	                            let state_str = zjjrpd_pace_state_str(&tack.state);
374	                            table.jjrp_write_row(&mut output, &[
375	                                &num.to_string(),
376	                                state_str,
377	                                &tack.silks,
378	                                coronet_key,
379	                            ]);
380	                        }
381	                    }
382	                }
383	            }
384	        }
385	
386	        // Always show file-touch bitmap and commit swim lanes after pace listing
387	        jjrpd_write_file_bitmap(&mut output, &firemark, heat);
388	        jjrpd_write_commit_swimlanes(&mut output, &firemark, heat);
389	
390	        // Add gazette notices for downstream consumption (detail mode only)
391	        if let Some(ref paddock_text) = gazette_paddock {
392	            gazette.jjrz_add(jjrz_Slug::Paddock, &heat_key, paddock_text).ok();
393	            for coronet_key in &heat.order {
394	                if let Some(pace) = heat.paces.get(coronet_key) {
395	                    if let Some(tack) = pace.tacks.first() {
396	                        if !args.remaining || (tack.state != PaceState::Complete && tack.state != PaceState::Abandoned) {
397	                            gazette.jjrz_add(jjrz_Slug::Pace, coronet_key, &tack.text).ok();
398	                        }
399	                    }
400	                }
401	            }
402	        }
403	    } else {
404	        vvco_err!(output, "{}: error: target must be Firemark (2 chars) or Coronet (5 chars), got {} chars", cn, target_str.len());
405	        return (1, output.vvco_finish());
406	    }
407	
408	    (0, output.vvco_finish())
409	}
410	
411	/// Format the file-touch bitmap for a heat as a String.
412	///
413	/// Uses shared query routines from jjrq_query to get file touches,
414	/// then formats as a bitmap with columns per pace and rows per file,
415	/// grouped by identical touch patterns.
416	pub fn jjrpd_format_file_bitmap(firemark: &Firemark, heat: &Heat) -> Result<String, String> {
417	    let touches = jjrq_file_touches_for_heat(firemark.jjrf_as_str())?;
418	
419	    // Build pace columns: only paces with commits, in heat order
420	    let mut pace_columns: Vec<(char, String, String)> = Vec::new();
421	    for coronet_key in &heat.order {
422	        if !touches.coronets_with_commits.contains(coronet_key) {
423	            continue;
424	        }
425	        if let Some(pace) = heat.paces.get(coronet_key) {
426	            if let Some(tack) = pace.tacks.first() {
427	                let raw = coronet_key.strip_prefix('₢').unwrap_or(coronet_key);
428	                if let Some(ch) = raw.chars().last() {
429	                    pace_columns.push((ch, coronet_key.clone(), tack.silks.clone()));
430	                }
431	            }
432	        }
433	    }
434	
435	    // Map coronet_display -> column index
436	    let mut coronet_to_col: BTreeMap<String, usize> = BTreeMap::new();
437	    for (idx, (_, coronet_display, _)) in pace_columns.iter().enumerate() {
438	        coronet_to_col.insert(coronet_display.clone(), idx);
439	    }
440	
441	    let total_cols = pace_columns.len();
442	
443	    // Build file -> touch vector from the shared query result
444	    let mut file_touches_map: BTreeMap<String, Vec<bool>> = BTreeMap::new();
445	
446	    for (coronet, files) in &touches.pace_files {
447	        if let Some(&col_idx) = coronet_to_col.get(coronet) {
448	            for filename in files {
449	                let row = file_touches_map.entry(filename.clone()).or_insert_with(|| vec![false; total_cols]);
450	                if col_idx < row.len() {
451	                    row[col_idx] = true;
452	                }
453	            }
454	        }
455	    }
456	
457	    let mut output = String::new();
458	
459	    if file_touches_map.is_empty() {
460	        writeln!(output, "File-touch bitmap: (no work file changes)").unwrap();
461	        return Ok(output);
462	    }
463	
464	    // Group files by identical touch pattern
465	    let mut pattern_groups: BTreeMap<Vec<bool>, Vec<String>> = BTreeMap::new();
466	    for (filename, pattern) in &file_touches_map {
467	        pattern_groups.entry(pattern.clone()).or_default().push(filename.clone());
468	    }
469	
470	    for files in pattern_groups.values_mut() {
471	        files.sort();
472	    }
473	
474	    // Header
475	    writeln!(output, "File-touch bitmap (x = pace commit touched file):").unwrap();
476	    writeln!(output).unwrap();
477	
478	    // Vertical legend
479	    for (i, (ch, _coronet, silks)) in pace_columns.iter().enumerate() {
480	        writeln!(output, "  {} {} {}", i + 1, ch, silks).unwrap();
481	    }
482	    writeln!(output).unwrap();
483	
484	    // Column header line (terminal chars aligned with bitmap positions)
485	    let header_chars: Vec<char> = pace_columns.iter().map(|(ch, _, _)| *ch).collect();
486	    let header_line: String = header_chars.iter().collect();
487	    writeln!(output, "{}", header_line).unwrap();
488	
489	    // Sort patterns: more touches first, then lexicographic
490	    let mut sorted_patterns: Vec<(Vec<bool>, Vec<String>)> = pattern_groups.into_iter().collect();
491	    sorted_patterns.sort_by(|(pat_a, _), (pat_b, _)| {
492	        let count_a: usize = pat_a.iter().filter(|&&b| b).count();
493	        let count_b: usize = pat_b.iter().filter(|&&b| b).count();
494	        count_b.cmp(&count_a).then_with(|| pat_a.cmp(pat_b))
495	    });
496	
497	    for (pattern, files) in &sorted_patterns {
498	        let bitmap: String = pattern.iter().map(|&b| if b { 'x' } else { '·' }).collect();
499	        writeln!(output, "{} {}", bitmap, files.join(", ")).unwrap();
500	    }
501	
502	    Ok(output)
503	}
504	
505	/// Write the file-touch bitmap for a heat to output.
506	pub(crate) fn jjrpd_write_file_bitmap(output: &mut vvco_Output, firemark: &Firemark, heat: &Heat) {
507	    let cn = JJRPD_CMD_NAME_SHOW;
508	    match jjrpd_format_file_bitmap(firemark, heat) {
509	        Ok(text) => {
510	            for line in text.lines() {
511	                vvco_out!(output, "{}", line);
512	            }
513	        }
514	        Err(e) => vvco_err!(output, "{}: error getting file touches: {}", cn, e),
515	    }
516	}
517	
518	/// Helper to convert PaceState to display string
519	pub(crate) fn zjjrpd_pace_state_str(state: &PaceState) -> &'static str {
520	    match state {
521	        PaceState::Rough => "rough",
522	        PaceState::Bridled => "bridled",
523	        PaceState::Complete => "complete",
524	        PaceState::Abandoned => "abandoned",
525	    }
526	}
527	
528	/// Resolve the default heat (first racing heat) when no target is specified
529	pub(crate) fn zjjrpd_resolve_default_heat(gallops: &Gallops) -> Result<String, String> {
530	    for (heat_key, heat) in &gallops.heats {
531	        if heat.status == HeatStatus::Racing {
532	            return Ok(heat_key.clone());
533	        }
534	    }
535	    Err("No racing heats found".to_string())
536	}
537	
538	/// Encode a column index as a dense character: 1-9 then a-z then A-Z (61 max)
539	fn zjjrpd_commit_index_char(index: usize) -> Option<char> {
540	    match index {
541	        0..=8 => Some((b'1' + index as u8) as char),
542	        9..=34 => Some((b'a' + (index - 9) as u8) as char),
543	        35..=60 => Some((b'A' + (index - 35) as u8) as char),
544	        _ => None,
545	    }
546	}
547	
548	/// Format commit swim lanes for a heat as a String: paces × commits matrix.
549	///
550	/// Shows when work happened on each pace and how work interleaved.
551	pub fn jjrpd_format_commit_swimlanes(firemark: &Firemark, heat: &Heat) -> Result<String, String> {
552	    let rein_args = jjrs_ReinArgs {
553	        firemark: firemark.jjrf_as_str().to_string(),
554	        limit: 10000,
555	    };
556	
557	    let entries = jjrs_get_entries(&rein_args)?;
558	
559	    if entries.is_empty() {
560	        return Ok(String::new());
561	    }
562	
563	    // Entries are newest-first; truncate to 35 most recent, then reverse for chronological
564	    let total_commits = entries.len();
565	    let max_commits: usize = 35;
566	    let truncated = total_commits > max_commits;
567	    let display_entries: Vec<&jjrs_SteeplechaseEntry> = entries
568	        .iter()
569	        .take(max_commits)
570	        .collect::<Vec<_>>()
571	        .into_iter()
572	        .rev()
573	        .collect();
574	
575	    // Build pace rows: ordered by first chronological appearance
576	    let mut pace_order: Vec<(String, char, String)> = Vec::new(); // (coronet_display, term_char, silks)
577	    let mut pace_index: BTreeMap<String, usize> = BTreeMap::new();
578	
579	    for entry in &display_entries {
580	        if let Some(ref coronet) = entry.coronet {
581	            if !pace_index.contains_key(coronet) {
582	                let idx = pace_order.len();
583	                let raw = coronet.strip_prefix('₢').unwrap_or(coronet);
584	                let ch = raw.chars().last().unwrap_or('?');
585	                let silks = heat.paces.get(coronet)
586	                    .and_then(|p| p.tacks.first())
587	                    .map(|t| t.silks.clone())
588	                    .unwrap_or_else(|| "unknown".to_string());
589	                pace_index.insert(coronet.clone(), idx);
590	                pace_order.push((coronet.clone(), ch, silks));
591	            }
592	        }
593	        // heat-level entries (no coronet) are intentionally excluded from swim lanes
594	    }
595	
596	    let total_rows = pace_order.len();
597	
598	    if total_rows == 0 {
599	        return Ok(String::new());
600	    }
601	
602	    // Build bitmap: rows × columns
603	    let num_cols = display_entries.len();
604	    let mut bitmap: Vec<Vec<bool>> = vec![vec![false; num_cols]; total_rows];
605	    let mut row_commit_counts: Vec<usize> = vec![0; total_rows];
606	
607	    for (col, entry) in display_entries.iter().enumerate() {
608	        if let Some(ref coronet) = entry.coronet {
609	            if let Some(&row) = pace_index.get(coronet) {
610	                bitmap[row][col] = true;
611	                row_commit_counts[row] += 1;
612	            }
613	        }
614	        // heat-level entries (no coronet) are intentionally excluded from swim lanes
615	    }
616	
617	    let mut output = String::new();
618	
619	    writeln!(output).unwrap();
620	    writeln!(output, "Commit swim lanes (x = commit affiliated with pace):").unwrap();
621	    writeln!(output).unwrap();
622	
623	    if truncated {
624	        writeln!(output, "(showing last {} of {} commits)", max_commits, total_commits).unwrap();
625	        writeln!(output).unwrap();
626	    }
627	
628	    // Vertical legend
629	    for (i, (_, ch, silks)) in pace_order.iter().enumerate() {
630	        writeln!(output, "  {} {} {}", i + 1, ch, silks).unwrap();
631	    }
632	    writeln!(output).unwrap();
633	
634	    // Column header line
635	    let header: String = (0..num_cols).filter_map(zjjrpd_commit_index_char).collect();
636	    writeln!(output, "{}", header).unwrap();
637	
638	    // Bitmap rows
639	    for row in 0..total_rows {
640	        let bits: String = bitmap[row].iter().map(|&b| if b { 'x' } else { '·' }).collect();
641	        let (term_char, count) = (pace_order[row].1, row_commit_counts[row]);
642	        writeln!(output, "{}  {}  {}c", bits, term_char, count).unwrap();
643	    }
644	
645	    Ok(output)
646	}
647	
648	/// Write commit swim lanes for a heat to output.
649	pub(crate) fn jjrpd_write_commit_swimlanes(output: &mut vvco_Output, firemark: &Firemark, heat: &Heat) {
650	    let cn = JJRPD_CMD_NAME_SHOW;
651	    match jjrpd_format_commit_swimlanes(firemark, heat) {
652	        Ok(text) => {
653	            for line in text.lines() {
654	                vvco_out!(output, "{}", line);
655	            }
656	        }
657	        Err(e) => vvco_err!(output, "{}: error getting steeplechase entries: {}", cn, e),
658	    }
659	}
660	
661	/// Write files-per-commit bitmap for a single pace to output.
662	///
663	/// Shows which files each commit in this pace touched.
664	/// Called after tack history in pace parade.
665	fn zjjrpd_write_pace_commits(output: &mut vvco_Output, firemark: &Firemark, coronet_key: &str) {
666	    let cn = JJRPD_CMD_NAME_SHOW;
667	    let rein_args = jjrs_ReinArgs {
668	        firemark: firemark.jjrf_as_str().to_string(),
669	        limit: 10000,
670	    };
671	
672	    let entries = match jjrs_get_entries(&rein_args) {
673	        Ok(e) => e,
674	        Err(e) => {
675	            vvco_err!(output, "{}: error getting steeplechase entries: {}", cn, e);
676	            return;
677	        }
678	    };
679	
680	    // Filter by coronet, then reverse for chronological order
681	    let pace_entries: Vec<&jjrs_SteeplechaseEntry> = entries
682	        .iter()
683	        .filter(|e| e.coronet.as_deref() == Some(coronet_key))
684	        .collect::<Vec<_>>()
685	        .into_iter()
686	        .rev()
687	        .collect();
688	
689	    if pace_entries.is_empty() {
690	        return;
691	    }
692	
693	    // Get files for each commit
694	    let num_commits = pace_entries.len();
695	    let mut file_touches: BTreeMap<String, Vec<bool>> = BTreeMap::new();
696	
697	    for (col, entry) in pace_entries.iter().enumerate() {
698	        let files = zjjrq_files_for_commit(&entry.commit);
699	        for path in files {
700	            if zjjrq_is_infra_file(&path) {
701	                continue;
702	            }
703	            let bare = zjjrq_bare_filename(&path);
704	            let row = file_touches.entry(bare).or_insert_with(|| vec![false; num_commits]);
705	            row[col] = true;
706	        }
707	    }
708	
709	    if file_touches.is_empty() {
710	        vvco_out!(output, "");
711	        vvco_out!(output, "Pace commits: (no project file commits)");
712	        return;
713	    }
714	
715	    vvco_out!(output, "");
716	    vvco_out!(output, "Pace commits (x = commit touched file):");
717	    vvco_out!(output, "");
718	
719	    // Legend: commit index char, SHA, subject
720	    for (i, entry) in pace_entries.iter().enumerate() {
721	        let ch = zjjrpd_commit_index_char(i).unwrap_or('?');
722	        vvco_out!(output, "  {} {}  {}", ch, entry.commit, entry.subject);
723	    }
724	    vvco_out!(output, "");
725	
726	    // Column header line
727	    let header: String = (0..num_commits).filter_map(zjjrpd_commit_index_char).collect();
728	    vvco_out!(output, "{}", header);
729	
730	    // Group by identical touch pattern
731	    let mut pattern_groups: BTreeMap<Vec<bool>, Vec<String>> = BTreeMap::new();
732	    for (filename, pattern) in &file_touches {
733	        pattern_groups.entry(pattern.clone()).or_default().push(filename.clone());
734	    }
735	    for files in pattern_groups.values_mut() {
736	        files.sort();
737	    }
738	
739	    // Sort: more touches first, then lexicographic
740	    let mut sorted: Vec<(Vec<bool>, Vec<String>)> = pattern_groups.into_iter().collect();
741	    sorted.sort_by(|(a, _), (b, _)| {
742	        let ca: usize = a.iter().filter(|&&v| v).count();
743	        let cb: usize = b.iter().filter(|&&v| v).count();
744	        cb.cmp(&ca).then_with(|| a.cmp(b))
745	    });
746	
747	    for (pattern, files) in &sorted {
748	        let bits: String = pattern.iter().map(|&b| if b { 'x' } else { '·' }).collect();
749	        vvco_out!(output, "{} {}", bits, files.join(", "));
750	    }
751	}
